const items = $input.all();

const response = {
  valido: true,
  resultado: "OK",
  detalle: "",
  nuevo_id_alumno: null
};

// Validación: input vacío
if (items.length === 0) {
  response.valido = false;
  response.resultado = "Error: no se recibieron alumnos en el input.";
  return [{ json: response }];
}

const ids = [];
const idSet = new Set();

for (let i = 0; i < items.length; i++) {
  const alumno = items[i].json;

  // 1. Existe id_alumno
  if (!("id_alumno" in alumno)) {
    response.valido = false;
    response.resultado = `Error: falta el campo id_alumno en el item índice ${i} (row_number ${alumno.row_number ?? "desconocido"}).`;
    return [{ json: response }];
  }

  const id = alumno.id_alumno;

  // 2. No null / undefined
  if (id === null || id === undefined) {
    response.valido = false;
    response.resultado = `Error: id_alumno nulo o indefinido en el item índice ${i}.`;
    return [{ json: response }];
  }

  // 3. Numérico
  if (typeof id !== "number" || Number.isNaN(id)) {
    response.valido = false;
    response.resultado = `Error: id_alumno no es numérico en el item índice ${i}. Valor recibido: ${id}.`;
    return [{ json: response }];
  }

  // 4. Unicidad
  if (idSet.has(id)) {
    response.valido = false;
    response.resultado = `Error: id_alumno duplicado detectado (${id}).`;
    return [{ json: response }];
  }

  idSet.add(id);
  ids.push(id);
}

// 5. Orden creciente estricto
for (let i = 1; i < ids.length; i++) {
  if (ids[i] <= ids[i - 1]) {
    response.valido = false;
    response.resultado =
      `Error: id_alumno fuera de orden creciente. ` +
      `Secuencia inválida: ${ids[i - 1]} → ${ids[i]} (índice ${i}).`;
    return [{ json: response }];
  }
}

// ✅ Todo OK → calcular nuevo ID
const maxId = Math.max(...ids);
response.nuevo_id_alumno = maxId + 1;

response.detalle =
  `Validación correcta. Cantidad de alumnos: ${items.length}. ` +
  `ID máximo actual: ${maxId}. Nuevo ID sugerido: ${response.nuevo_id_alumno}.`;

return [{ json: response }];
